     1→#!/usr/bin/env node
     2→/**
     3→ * Harness Orchestrator CLI
     4→ *
     5→ * Command-line interface for the harness orchestrator.
     6→ */
     7→
     8→import { Command } from 'commander';
     9→import chalk from 'chalk';
    10→import ora from 'ora';
    11→import { readFileSync } from 'node:fs';
    12→import { resolve } from 'node:path';
    13→
    14→import { DependencyGraph } from '../graph/DependencyGraph.js';
    15→import { CriticalPath } from '../graph/CriticalPath.js';
    16→import { StateManager } from '../state/StateManager.js';
    17→import { AIManager } from '../ai/AIManager.js';
    18→import { Orchestrator } from '../orchestrator/Orchestrator.js';
    19→import { Dashboard } from '../dashboard/Dashboard.js';
    20→import { Verifier } from '../verification/Verifier.js';
    21→import {
    22→  getAllHookTemplates,
    23→  getSettingsTemplate,
    24→} from '../hooks/HookTemplates.js';
    25→import type { HarnessConfig, ModelType } from '../types.js';
    26→
    27→const program = new Command();
    28→
    29→program
    30→  .name('harness')
    31→  .alias('h')
    32→  .description('AI Project Manager for harness task orchestration')
    33→  .version('0.1.0');
    34→
    35→// Default features path
    36→const DEFAULT_FEATURES_PATH = 'features.json';
    37→
    38→/**
    39→ * Resolve features path, using default if not provided
    40→ */
    41→function resolveFeaturesPath(path?: string): string {
    42→  return resolve(path || DEFAULT_FEATURES_PATH);
    43→}
    44→
    45→// Analyze command
    46→program
    47→  .command('analyze [features-path]')
    48→  .description('Analyze dependency graph and show execution plan')
    49→  .action((featuresPath?: string) => {
    50→    const resolvedPath = resolveFeaturesPath(featuresPath);
    51→    const content = readFileSync(resolvedPath, 'utf-8');
    52→    const config: HarnessConfig = JSON.parse(content);
    53→
    54→    const graph = new DependencyGraph(config);
    55→    const criticalPath = new CriticalPath(graph);
    56→
    57→    console.log(chalk.bold('\n📊 Dependency Analysis\n'));
    58→
    59→    // Check for cycles
    60→    const cycle = graph.detectCycles();
    61→    if (cycle) {
    62→      console.log(chalk.red('❌ Cycle detected:'), cycle.join(' → '));
    63→      process.exit(1);
    64→    }
    65→    console.log(chalk.green('✓ No cycles detected\n'));
    66→
    67→    // Show features by status
    68→    const pending = graph.getPendingFeatures();
    69→    const completed = graph.getAllFeatures().filter((f) => f.passes);
    70→
    71→    console.log(chalk.bold('Status:'));
    72→    console.log(`  Completed: ${chalk.green(completed.length)}`);
    73→    console.log(`  Pending: ${chalk.yellow(pending.length)}`);
    74→    console.log();
    75→
    76→    // Show ready tasks
    77→    const ready = graph.getReadyTasks();
    78→    console.log(chalk.bold('Ready to run (parallelizable):'));
    79→    if (ready.length === 0) {
    80→      console.log(chalk.dim('  None'));
    81→    } else {
    82→      for (const f of ready) {
    83→        const priority = criticalPath.getPriorityScore(f.id);
    84→        const onCritical = criticalPath.getCriticalPath().includes(f.id);
    85→        const critical = onCritical ? chalk.red(' [CRITICAL]') : '';
    86→        console.log(`  ${chalk.cyan(f.id)}: ${f.description}${critical} (priority: ${priority})`);
    87→      }
    88→    }
    89→    console.log();
    90→
    91→    // Show critical path
    92→    const path = criticalPath.getCriticalPath();
    93→    console.log(chalk.bold('Critical Path:'));
    94→    console.log(`  ${path.map((id) => chalk.red(id)).join(' → ')}`);
    95→    console.log();
    96→
    97→    // Show execution order
    98→    const order = graph.topologicalSort();
    99→    console.log(chalk.bold('Topological Order:'));
   100→    console.log(`  ${order.map((id) => graph.getFeature(id)?.passes ? chalk.green(id) : chalk.yellow(id)).join(' → ')}`);
   101→  });
   102→
   103→// Status command
   104→program
   105→  .command('status [features-path]')
   106→  .description('Show current progress status')
   107→  .action((featuresPath?: string) => {
   108→    const resolvedPath = resolveFeaturesPath(featuresPath);
   109→    const stateManager = new StateManager(resolvedPath);
   110→    const aiManager = new AIManager();
   111→
   112→    const config = stateManager.load();
   113→    const progress = stateManager.getProgress();
   114→
   115→    console.log(chalk.bold('\n📈 Harness Status\n'));
   116→    console.log(`Project: ${chalk.cyan(config.project)}`);
   117→    console.log(`Version: ${config.version}`);
   118→    console.log(`Last Updated: ${config.lastUpdated}`);
   119→    console.log();
   120→
   121→    // Progress bar
   122→    const pct = Math.round((progress.completed / progress.total) * 100);
   123→    const filled = Math.round(pct / 5);
   124→    const bar = '█'.repeat(filled) + '░'.repeat(20 - filled);
   125→    console.log(`Progress: [${bar}] ${pct}%`);
   126→    console.log(`  ${chalk.green(progress.completed)} completed / ${chalk.yellow(progress.pending)} pending`);
   127→    console.log();
   128→
   129→    // Features list
   130→    console.log(chalk.bold('Features:'));
   131→    for (const f of config.features) {
   132→      const status = f.passes ? chalk.green('✓') : chalk.yellow('○');
   133→      const blockedBy = f.blockedBy
   134→        ? chalk.dim(` (blocked by: ${Array.isArray(f.blockedBy) ? f.blockedBy.join(', ') : f.blockedBy})`)
   135→        : '';
   136→      console.log(`  ${status} ${f.id}: ${f.description}${blockedBy}`);
   137→    }
   138→
   139→    // AI summary
   140→    console.log('\n' + aiManager.generateProgressSummary(config.features));
   141→  });
   142→
   143→// Orchestrate command
   144→program
   145→  .command('orchestrate [features-path]')
   146→  .description('Run full orchestration with parallel agents')
   147→  .option('-n, --max-agents <number>', 'Maximum concurrent agents', '3')
   148→  .option('-m, --model <model>', 'Default model (haiku, sonnet, opus)', 'sonnet')
   149→  .option('--dry-run', 'Show plan without executing')
   150→  .option('--timeout <ms>', 'Timeout per task in milliseconds', '600000')
   151→  .option('-d, --dashboard', 'Enable real-time dashboard UI')
   152→  .option('--no-costs', 'Disable cost estimates in dashboard')
   153→  .action(async (featuresPath: string | undefined, options) => {
   154→    const spinner = ora('Loading harness configuration...').start();
   155→
   156→    try {
   157→      const resolvedPath = resolveFeaturesPath(featuresPath);
   158→      const stateManager = new StateManager(resolvedPath);
   159→      const config = stateManager.load();
   160→
   161→      spinner.succeed('Configuration loaded');
   162→
   163→      const pending = config.features.filter((f) => !f.passes).length;
   164→
   165→      if (options.dryRun) {
   166→        console.log(chalk.yellow('\n🔍 Dry Run Mode\n'));
   167→        console.log('Would orchestrate with:');
   168→        console.log(`  Max agents: ${options.maxAgents}`);
   169→        console.log(`  Model: ${options.model}`);
   170→        console.log(`  Features: ${pending} pending`);
   171→        console.log(`  Dashboard: ${options.dashboard ? 'enabled' : 'disabled'}`);
   172→        return;
   173→      }
   174→
   175→      if (pending === 0) {
   176→        console.log(chalk.green('\n✅ All features are already complete!'));
   177→        return;
   178→      }
   179→
   180→      const orchestrator = new Orchestrator(resolvedPath, {
   181→        maxAgents: parseInt(options.maxAgents, 10),
   182→        model: options.model as ModelType,
   183→        timeout: parseInt(options.timeout, 10),
   184→      });
   185→
   186→      if (options.dashboard) {
   187→        // Use real-time dashboard
   188→        const dashboard = new Dashboard(config, {
   189→          liveRefresh: true,
   190→          showCosts: options.costs !== false,
   191→          maxAgents: parseInt(options.maxAgents, 10),
   192→        });
   193→        dashboard.setModel(options.model as 'haiku' | 'sonnet' | 'opus');
   194→        dashboard.attach(orchestrator);
   195→
   196→        const result = await orchestrator.run();
   197→        dashboard.renderFinalSummary();
   198→
   199→        if (result.failed > 0) {
   200→          process.exit(1);
   201→        }
   202→      } else {
   203→        // Classic output mode
   204→        console.log(chalk.bold('\n🚀 Starting Orchestration\n'));
   205→        console.log(`  Max agents: ${chalk.cyan(options.maxAgents)}`);
   206→        console.log(`  Model: ${chalk.cyan(options.model)}`);
   207→        console.log(`  Pending: ${chalk.yellow(pending)} features`);
   208→        console.log();
   209→
   210→        // Event handlers for progress display
   211→        orchestrator.on('taskDispatched', ({ taskId, feature }) => {
   212→          console.log(chalk.blue(`▶ Started ${taskId}: ${feature.description}`));
   213→        });
   214→
   215→        orchestrator.on('taskSucceeded', ({ taskId }) => {
   216→          console.log(chalk.green(`✓ Completed ${taskId}`));
   217→        });
   218→
   219→        orchestrator.on('taskFailed', ({ taskId, error }) => {
   220→          console.log(chalk.red(`✗ Failed ${taskId}: ${error}`));
   221→        });
   222→
   223→        orchestrator.on('deadlock', ({ pending }) => {
   224→          console.log(chalk.red(`\n⚠️  Deadlock detected! ${pending} tasks stuck.`));
   225→        });
   226→
   227→        orchestrator.on('shutdown', ({ signal }) => {
   228→          console.log(chalk.yellow(`\n⚠️  Received ${signal}, shutting down gracefully...`));
   229→        });
   230→
   231→        const runSpinner = ora('Running orchestration...').start();
   232→        const result = await orchestrator.run();
   233→        runSpinner.stop();
   234→
   235→        console.log(chalk.bold('\n📊 Results\n'));
   236→        console.log(`  Completed: ${chalk.green(result.completed)}`);
   237→        console.log(`  Failed: ${chalk.red(result.failed)}`);
   238→
   239→        if (result.failed === 0) {
   240→          console.log(chalk.green('\n✅ Orchestration completed successfully!'));
   241→        } else {
   242→          console.log(chalk.yellow(`\n⚠️  ${result.failed} task(s) failed.`));
   243→          process.exit(1);
   244→        }
   245→      }
   246→    } catch (error) {
   247→      spinner.fail('Orchestration failed');
   248→      console.error(error);
   249→      process.exit(1);
   250→    }
   251→  });
   252→
   253→// Dashboard command (standalone)
   254→program
   255→  .command('dashboard [features-path]')
   256→  .description('Show real-time dashboard (attaches to running orchestration)')
   257→  .option('--no-costs', 'Disable cost estimates')
   258→  .action((featuresPath: string | undefined, options) => {
   259→    const resolvedPath = resolveFeaturesPath(featuresPath);
   260→    const stateManager = new StateManager(resolvedPath);
   261→    const config = stateManager.load();
   262→
   263→    const dashboard = new Dashboard(config, {
   264→      liveRefresh: false,
   265→      showCosts: options.costs !== false,
   266→    });
   267→
   268→    dashboard.render();
   269→  });
   270→
   271→// Verify command
   272→program
   273→  .command('verify [features-path]')
   274→  .description('Verify feature completion and show verification status')
   275→  .option('-f, --feature <id>', 'Verify a specific feature')
   276→  .option('--all', 'Verify all completed features')
   277→  .action(async (featuresPath: string | undefined, options) => {
   278→    const resolvedPath = resolveFeaturesPath(featuresPath);
   279→    const verifier = new Verifier(resolvedPath);
   280→    const stateManager = new StateManager(resolvedPath);
   281→    const config = stateManager.load();
   282→
   283→    console.log(chalk.bold('\n🔍 Feature Verification\n'));
   284→
   285→    // Get git status
   286→    const gitStatus = verifier.getGitStatus();
   287→    if (gitStatus) {
   288→      console.log(chalk.bold('Git Status:'));
   289→      console.log(`  Branch: ${chalk.cyan(gitStatus.branch)}`);
   290→      console.log(`  Clean: ${gitStatus.isClean ? chalk.green('Yes') : chalk.yellow('No')}`);
   291→      if (gitStatus.ahead > 0 || gitStatus.behind > 0) {
   292→        console.log(`  Ahead: ${gitStatus.ahead}, Behind: ${gitStatus.behind}`);
   293→      }
   294→      console.log();
   295→    }
   296→
   297→    // List feature branches
   298→    const branches = verifier.listFeatureBranches();
   299→    if (branches.length > 0) {
   300→      console.log(chalk.bold('Feature Branches:'));
   301→      for (const branch of branches) {
   302→        const status = branch.isMerged ? chalk.green('merged') : chalk.yellow('pending');
   303→        console.log(`  ${branch.name} (${branch.featureId}) - ${status}`);
   304→      }
   305→      console.log();
   306→    }
   307→
   308→    // Verify features
   309→    const featuresToVerify = options.feature
   310→      ? config.features.filter(f => f.id === options.feature)
   311→      : options.all
   312→        ? config.features.filter(f => f.passes)
   313→        : config.features.filter(f => f.passes).slice(0, 5);
   314→
   315→    if (featuresToVerify.length === 0) {
   316→      console.log(chalk.dim('No features to verify'));
   317→      return;
   318→    }
   319→
   320→    console.log(chalk.bold('Verification Results:'));
   321→    for (const feature of featuresToVerify) {
   322→      const result = await verifier.verifyFeature(feature);
   323→      const icon = result.passed ? chalk.green('✓') : chalk.red('✗');
   324→      console.log(`\n${icon} ${chalk.bold(result.featureId)}: ${feature.description}`);
   325→      for (const check of result.checks) {
   326→        const checkIcon = check.passed ? chalk.green('✓') : chalk.red('✗');
   327→        console.log(`    ${checkIcon} ${check.name}: ${chalk.dim(check.details || '')}`);
   328→      }
   329→    }
   330→  });
   331→
   332→// Rollback command
   333→program
   334→  .command('rollback [features-path]')
   335→  .description('Rollback a feature to its previous state')
   336→  .requiredOption('-f, --feature <id>', 'Feature ID to rollback')
   337→  .option('--delete-remote', 'Also delete remote branch')
   338→  .action(async (featuresPath: string | undefined, options) => {
   339→    const resolvedPath = resolveFeaturesPath(featuresPath);
   340→    const verifier = new Verifier(resolvedPath);
   341→    const stateManager = new StateManager(resolvedPath);
   342→
   343→    const featureId = options.feature.toUpperCase();
   344→
   345→    console.log(chalk.bold(`\n🔄 Rolling back feature ${featureId}\n`));
   346→
   347→    const gitStatus = verifier.getGitStatus();
   348→    if (!gitStatus) {
   349→      console.log(chalk.red('Not a git repository. Cannot rollback.'));
   350→      process.exit(1);
   351→    }
   352→
   353→    const branches = verifier.listFeatureBranches();
   354→    const branch = branches.find(b => b.featureId === featureId);
   355→
   356→    if (!branch) {
   357→      console.log(chalk.yellow(`No branch found for feature ${featureId}`));
   358→      console.log('Available feature branches:');
   359→      for (const b of branches) {
   360→        console.log(`  - ${b.name} (${b.featureId})`);
   361→      }
   362→      return;
   363→    }
   364→
   365→    console.log(`Branch: ${chalk.cyan(branch.name)}`);
   366→    console.log(`Merged: ${branch.isMerged ? chalk.green('Yes') : chalk.yellow('No')}`);
   367→    console.log();
   368→
   369→    // Update state to mark as not complete
   370→    const config = stateManager.load();
   371→    const feature = config.features.find(f => f.id === featureId);
   372→    if (feature) {
   373→      feature.passes = false;
   374→      await stateManager.save(config);
   375→      console.log(chalk.green(`✓ Marked ${featureId} as incomplete in features.json`));
   376→    }
   377→
   378→    // Note: In a real implementation, we'd use the GitManager to delete the branch
   379→    console.log(chalk.dim(`To delete the branch manually: git branch -D ${branch.name}`));
   380→
   381→    console.log(chalk.green('\n✓ Rollback complete'));
   382→  });
   383→
   384→// Branches command
   385→program
   386→  .command('branches [features-path]')
   387→  .description('List and manage feature branches')
   388→  .option('--cleanup', 'Delete merged feature branches')
   389→  .action((featuresPath: string | undefined, options) => {
   390→    const resolvedPath = resolveFeaturesPath(featuresPath);
   391→    const verifier = new Verifier(resolvedPath);
   392→
   393→    const gitStatus = verifier.getGitStatus();
   394→    if (!gitStatus) {
   395→      console.log(chalk.red('Not a git repository.'));
   396→      process.exit(1);
   397→    }
   398→
   399→    console.log(chalk.bold('\n🌿 Feature Branches\n'));
   400→    console.log(`Current branch: ${chalk.cyan(gitStatus.branch)}`);
   401→    console.log();
   402→
   403→    const branches = verifier.listFeatureBranches();
   404→
   405→    if (branches.length === 0) {
   406→      console.log(chalk.dim('No feature branches found'));
   407→      return;
   408→    }
   409→
   410→    const merged = branches.filter(b => b.isMerged);
   411→    const pending = branches.filter(b => !b.isMerged);
   412→
   413→    if (pending.length > 0) {
   414→      console.log(chalk.bold('Pending (not merged):'));
   415→      for (const branch of pending) {
   416→        console.log(`  ${chalk.yellow('○')} ${branch.name} (${branch.featureId})`);
   417→      }
   418→      console.log();
   419→    }
   420→
   421→    if (merged.length > 0) {
   422→      console.log(chalk.bold('Merged:'));
   423→      for (const branch of merged) {
   424→        console.log(`  ${chalk.green('✓')} ${branch.name} (${branch.featureId})`);
   425→      }
   426→      console.log();
   427→    }
   428→
   429→    if (options.cleanup && merged.length > 0) {
   430→      console.log(chalk.bold('Cleaning up merged branches...'));
   431→      const deleted = verifier.cleanupMergedBranches();
   432→      console.log(chalk.green(`✓ Deleted ${deleted.length} branch(es)`));
   433→    } else if (merged.length > 0) {
   434→      console.log(chalk.dim(`Run with --cleanup to delete ${merged.length} merged branch(es)`));
   435→    }
   436→  });
   437→
   438→// Init command - bootstrap a new harness project
   439→program
   440→  .command('init [project-path]')
   441→  .description('Initialize a new harness project with standard structure')
   442→  .option('-n, --name <name>', 'Project name')
   443→  .option('--no-hooks', 'Skip generating hooks')
   444→  .option('--no-git', 'Skip git initialization')
   445→  .action(async (projectPath: string | undefined, options) => {
   446→    const targetDir = resolve(projectPath || '.');
   447→    const projectName = options.name || targetDir.split('/').pop() || 'my-project';
   448→
   449→    console.log(chalk.bold(`\n🚀 Initializing Harness Project: ${projectName}\n`));
   450→
   451→    const { existsSync, mkdirSync, writeFileSync } = await import('node:fs');
   452→
   453→    // Create directory if needed
   454→    if (!existsSync(targetDir)) {
   455→      mkdirSync(targetDir, { recursive: true });
   456→      console.log(chalk.green(`✓ Created directory: ${targetDir}`));
   457→    }
   458→
   459→    // 1. Generate features.json
   460→    const featuresPath = resolve(targetDir, 'features.json');
   461→    if (!existsSync(featuresPath)) {
   462→      const featuresTemplate = {
   463→        project: projectName,
   464→        version: '0.1.0',
   465→        description: `Harness configuration for ${projectName}`,
   466→        lastUpdated: new Date().toISOString().split('T')[0],
   467→        features: [
   468→          {
   469→            id: 'F001',
   470→            category: 'setup',
   471→            description: 'Project initialization and environment setup',
   472→            steps: [
   473→              'Verify development environment',
   474→              'Install dependencies',
   475→              'Configure build tools',
   476→              'Run initial build'
   477→            ],
   478→            passes: false,
   479→            blockedBy: null,
   480→            notes: 'First feature - no dependencies'
   481→          }
   482→        ]
   483→      };
   484→      writeFileSync(featuresPath, JSON.stringify(featuresTemplate, null, 2));
   485→      console.log(chalk.green('✓ Created features.json'));
   486→    } else {
   487→      console.log(chalk.yellow('○ features.json already exists, skipping'));
   488→    }
   489→
   490→    // 2. Generate claude-progress.txt
   491→    const progressPath = resolve(targetDir, 'claude-progress.txt');
   492→    if (!existsSync(progressPath)) {
   493→      const today = new Date().toISOString().split('T')[0];
   494→      const progressTemplate = `# ${projectName} - Progress Log
   495→
   496→## Project Goal
   497→[Describe the main objective of this project]
   498→
   499→---
   500→
   501→## Session 1 - ${today} - Project Initialization
   502→
   503→### Context
   504→Initial harness setup.
   505→
   506→### Completed ✅
   507→- Created harness structure with \`harness init\`
   508→- Generated features.json with initial feature
   509→
   510→### Current State
   511→| Feature | Status | Notes |
   512→|---------|--------|-------|
   513→| F001 | ○ Pending | Project setup |
   514→
   515→### Next Session Priorities
   516→1. Complete F001: Project initialization
   517→2. Add more features to features.json
   518→
   519→---
   520→
   521→## Quick Start for New Session
   522→
   523→\`\`\`bash
   524→# 1. Read current state
   525→harness status
   526→
   527→# 2. Work on next feature
   528→# ... implement ...
   529→
   530→# 3. Mark complete and commit
   531→# Update features.json: passes: true
   532→git add . && git commit -m "feat: F001 - description"
   533→
   534→# 4. Update this progress file
   535→\`\`\`
   536→`;
   537→      writeFileSync(progressPath, progressTemplate);
   538→      console.log(chalk.green('✓ Created claude-progress.txt'));
   539→    } else {
   540→      console.log(chalk.yellow('○ claude-progress.txt already exists, skipping'));
   541→    }
   542→
   543→    // 3. Generate CLAUDE.md
   544→    const claudeMdPath = resolve(targetDir, 'CLAUDE.md');
   545→    if (!existsSync(claudeMdPath)) {
   546→      const claudeMdTemplate = `# ${projectName} - AI Instructions
   547→
   548→## What is This?
   549→
   550→This project uses a **Harness** - a framework that enables AI agents to work on long tasks across multiple context windows/sessions.
   551→
   552→**Problem:** Each new Claude Code session starts with NO memory of previous sessions.
   553→**Solution:** State files persist context between sessions.
   554→
   555→---
   556→
   557→## Harness Protocol
   558→
   559→\`\`\`
   560→1. READ claude-progress.txt → understand current state
   561→2. READ features.json → find next feature (passes: false)
   562→3. IMPLEMENT the feature
   563→4. TEST the implementation
