// Continue command - the CORE harness command per Anthropic protocol
program
  .command('continue [project-path]')
  .description('Continue working on the harness (Two-Agent Architecture per Anthropic)')
  .option('-m, --model <model>', 'Model to use (haiku, sonnet, opus)', 'sonnet')
  .option('--timeout <ms>', 'Timeout per feature in milliseconds', '600000')
  .option('--dry-run', 'Show what would be done without executing')
  .option('--init-only', 'Only run initializer, do not start coding agent')
  .action(async (projectPath: string | undefined, options) => {
    const targetDir = resolve(projectPath || '.');
    const progressPath = resolve(targetDir, 'claude-progress.txt');
    const featuresPath = resolve(targetDir, 'features.json');
    const initShPath = resolve(targetDir, 'init.sh');

    const { existsSync, readFileSync } = await import('node:fs');
    const { execSync, spawn } = await import('node:child_process');

    console.log(chalk.bold('\n🚀 Harness Continue\n'));
    console.log(chalk.dim(`Project: ${targetDir}`));
    console.log(chalk.dim(`Model: ${options.model}`));
    console.log();

    // Determine if this is first run (Initializer) or subsequent (Coding Agent)
    const isFirstRun = !existsSync(progressPath);

    if (isFirstRun) {
      console.log(chalk.yellow('📋 First run detected - Initializer Agent mode\n'));

      if (options.dryRun) {
        console.log(chalk.cyan('Dry run: Would spawn Initializer Agent to:'));
        console.log('  1. Create claude-progress.txt');
        console.log('  2. Create init.sh if needed');
        console.log('  3. Set up project structure');
        return;
      }

      // Check if harness is already initialized
      if (!existsSync(featuresPath)) {
        console.log(chalk.yellow('⚠️  No harness structure found.'));
        console.log();
        console.log('Run the following to initialize:');
        console.log(chalk.cyan(`  harness init ${projectPath || '.'}`));
        return;
      }

      // Create initial progress file
      console.log('Creating initial claude-progress.txt...');

      // Read features to understand the project
      const featuresData = JSON.parse(readFileSync(featuresPath, 'utf-8'));
      const projectName = featuresData.project || 'Project';

      const today = new Date().toISOString().split('T')[0];
      const initialProgress = `# ${projectName} - Progress Log

## Project Goal
${featuresData.description || '[Describe the main objective of this project]'}

---

## Session 1 - ${today} - Initializer Agent

### Context
Initial harness setup by Initializer Agent.

### Completed ✅
- Created claude-progress.txt
- Verified harness structure exists

### Current State
| Feature | Status | Notes |
|---------|--------|-------|
${featuresData.features.slice(0, 10).map((f: { id: string; passes: boolean; description: string }) =>
  `| ${f.id} | ${f.passes ? '✅ Complete' : '○ Pending'} | ${f.description.slice(0, 40)}... |`
).join('\n')}

### Next Session Priorities
1. Work on first incomplete feature
2. Run visual tests with Playwright MCP
3. Commit changes after feature passes

---

## Quick Start for Coding Agent

\`\`\`bash
# 1. Read current state
harness status

# 2. Pick first incomplete feature from features.json
# 3. Implement the feature
# 4. Test with Playwright MCP

# 5. Update features.json: passes: true
# 6. Commit changes
# 7. Run harness continue again
\`\`\`
`;

      const { writeFileSync } = await import('node:fs');
      writeFileSync(progressPath, initialProgress);
      console.log(chalk.green('✓ Created claude-progress.txt'));

      // Run init.sh if it exists
      if (existsSync(initShPath)) {
        console.log('Running init.sh...');
        try {
          execSync(`bash "${initShPath}"`, { cwd: targetDir, stdio: 'inherit' });
          console.log(chalk.green('✓ init.sh completed'));
        } catch (error) {
          console.log(chalk.yellow('⚠️  init.sh had issues (non-fatal)'));
        }
      }

      console.log(chalk.green('\n✅ Initialization complete!\n'));

      if (options.initOnly) {
        console.log('--init-only specified, stopping here.');
        return;
      }

      console.log('Next: Spawning Coding Agent...\n');
      // Fall through to coding agent
    } else {
      console.log(chalk.cyan('📝 Coding Agent mode\n'));
    }

    // CODING AGENT LOGIC

    // 1. Read progress and features
    if (!existsSync(featuresPath)) {
      console.log(chalk.red('❌ features.json not found'));
      return;
    }

    const featuresData = JSON.parse(readFileSync(featuresPath, 'utf-8'));

    // 2. Find next incomplete feature (highest priority)
    const graph = new DependencyGraph(featuresData);
    const readyTasks = graph.getReadyTasks();

    if (readyTasks.length === 0) {
      const pending = graph.getPendingFeatures();
      if (pending.length === 0) {
        console.log(chalk.green('🎉 All features are complete!'));
        return;
      } else {
        console.log(chalk.yellow('⚠️  No features are ready to work on.'));
        console.log(chalk.dim('All pending features are blocked by incomplete dependencies.'));
        console.log();
        console.log('Blocked features:');
        for (const f of pending) {
          const blockedBy = Array.isArray(f.blockedBy) ? f.blockedBy.join(', ') : f.blockedBy;
          console.log(`  ${chalk.yellow('○')} ${f.id}: ${f.description}`);
          console.log(chalk.dim(`      Blocked by: ${blockedBy}`));
        }
        return;
      }
    }

    // Get critical path to prioritize
    const criticalPath = new CriticalPath(graph);
    const criticalPathIds = criticalPath.getCriticalPath();

    // Sort ready tasks by priority (critical path first)
    readyTasks.sort((a, b) => {
      const aOnCritical = criticalPathIds.includes(a.id);
      const bOnCritical = criticalPathIds.includes(b.id);
      if (aOnCritical && !bOnCritical) return -1;
      if (!aOnCritical && bOnCritical) return 1;
      return criticalPath.getPriorityScore(b.id) - criticalPath.getPriorityScore(a.id);
    });

    const nextFeature = readyTasks[0];

    console.log(chalk.bold('Next Feature to Work On:'));
    console.log(`  ${chalk.cyan(nextFeature.id)}: ${nextFeature.description}`);
    if (criticalPathIds.includes(nextFeature.id)) {
      console.log(chalk.red('  [ON CRITICAL PATH]'));
    }
    console.log();

    if (nextFeature.steps && nextFeature.steps.length > 0) {
      console.log(chalk.bold('Steps:'));
      for (let i = 0; i < nextFeature.steps.length; i++) {
        console.log(`  ${i + 1}. ${nextFeature.steps[i]}`);
      }
      console.log();
    }

    if (options.dryRun) {
      console.log(chalk.cyan('Dry run: Would spawn Claude to work on this feature.'));
      console.log();
      console.log('To execute, run without --dry-run:');
      console.log(chalk.cyan(`  harness continue ${projectPath || ''}`));
      return;
    }

    // 3. Spawn Claude agent to work on the feature
    console.log(chalk.bold('Spawning Claude agent...\n'));

    const prompt = `You are working on feature ${nextFeature.id}: "${nextFeature.description}".

Current project: ${featuresData.project}
Working directory: ${targetDir}

IMPORTANT - Follow the Harness Protocol:
1. Read claude-progress.txt to understand context
2. Implement ONLY this ONE feature: ${nextFeature.id}
3. Test with Playwright MCP (visual verification required!)
4. Update features.json: set passes: true for ${nextFeature.id}
5. Update claude-progress.txt with session notes
6. Commit your changes with descriptive message

Steps for this feature:
${nextFeature.steps ? nextFeature.steps.map((s: string, i: number) => `${i + 1}. ${s}`).join('\n') : '(No specific steps defined)'}

Notes: ${nextFeature.notes || '(none)'}

Begin implementation now. Work autonomously until this feature is complete.`;

    console.log(chalk.dim('Prompt:'));
    console.log(chalk.dim('─'.repeat(60)));
    console.log(chalk.dim(prompt.split('\n').map(l => '  ' + l).join('\n')));
    console.log(chalk.dim('─'.repeat(60)));
    console.log();

    // Spawn Claude Code CLI
    const claudeArgs = [
      '--print',
      '--dangerously-skip-permissions',
      prompt
    ];

    console.log(chalk.dim(`Running: claude ${claudeArgs.slice(0, 2).join(' ')} "..."`));
    console.log();

    try {
      const claudeProcess = spawn('claude', claudeArgs, {
        cwd: targetDir,
        stdio: 'inherit',
        shell: true,
      });

      claudeProcess.on('error', (error) => {
        console.log(chalk.red('\n❌ Failed to spawn Claude:'));
        console.log(chalk.dim(error.message));
        console.log();
        console.log('Make sure Claude Code CLI is installed:');
        console.log(chalk.cyan('  npm install -g @anthropic-ai/claude-code'));
      });

      claudeProcess.on('close', (code) => {
        console.log();
        if (code === 0) {
          console.log(chalk.green('✅ Claude agent completed successfully'));
          console.log();
          console.log('Next steps:');
          console.log(`  1. Verify ${chalk.cyan('features.json')} has ${nextFeature.id} marked as passes: true`);
          console.log(`  2. Run ${chalk.cyan('harness continue')} to work on next feature`);
        } else {
          console.log(chalk.yellow(`⚠️  Claude agent exited with code ${code}`));
          console.log();
          console.log('The agent may have encountered an issue. Check:');
          console.log(`  1. ${chalk.cyan('claude-progress.txt')} for session notes`);
          console.log(`  2. Git status for any uncommitted changes`);
          console.log(`  3. Run ${chalk.cyan('harness continue')} to retry`);
        }
      });
    } catch (error) {
      console.log(chalk.red('❌ Error spawning Claude:'));
      console.log(chalk.dim(String(error)));
    }
  });

// Session command - create new session entry in progress file
program
  .command('session [project-path]')
  .description('Create a new session entry in claude-progress.txt')
  .option('-t, --title <title>', 'Session title/description')
  .action(async (projectPath: string | undefined, options) => {
    const targetDir = resolve(projectPath || '.');
    const progressPath = resolve(targetDir, 'claude-progress.txt');
    const featuresPath = resolve(targetDir, 'features.json');

    const { existsSync, readFileSync, appendFileSync } = await import('node:fs');

    if (!existsSync(progressPath)) {
      console.log(chalk.red('❌ claude-progress.txt not found'));
      console.log(chalk.dim(`Expected at: ${progressPath}`));
      console.log(chalk.dim('Run "harness init" first to create the harness structure.'));
      process.exit(1);
    }

    // Read current progress to determine session number
    const currentProgress = readFileSync(progressPath, 'utf-8');
    const sessionMatches = currentProgress.match(/## Session (\d+)/g);
    const nextSessionNum = sessionMatches ? sessionMatches.length + 1 : 1;

    const today = new Date().toISOString().split('T')[0];
    const title = options.title || 'New Session';

    // Get feature status if available
    let featureStatus = '';
    if (existsSync(featuresPath)) {
      try {
        const featuresData = JSON.parse(readFileSync(featuresPath, 'utf-8'));
        const pending = featuresData.features.filter((f: { passes: boolean }) => !f.passes);
        const completed = featuresData.features.filter((f: { passes: boolean }) => f.passes);

        featureStatus = `
### Current State

| Feature | Status | Notes |
|---------|--------|-------|
`;
        for (const f of featuresData.features.slice(0, 10)) {
          const status = f.passes ? '✅ Complete' : '🔓 Pending';
          featureStatus += `| ${f.id} | ${status} | ${f.description.slice(0, 40)}... |\n`;
        }
        if (featuresData.features.length > 10) {
          featureStatus += `| ... | ... | ${featuresData.features.length - 10} more features |\n`;
        }

        featureStatus += `
### Summary
- Completed: ${completed.length}
- Pending: ${pending.length}
`;
      } catch {
        featureStatus = '\n### Features\n(Unable to parse features.json)\n';
      }
    }

    const sessionEntry = `
---

## Session ${nextSessionNum} - ${today} - ${title}

### Context
[Describe the goal of this session]

### Completed ✅
- [List completed tasks]

### In Progress 🔄
- [List tasks in progress]

### Blocked ⚠️
- [List blocked tasks and why]
${featureStatus}
### Next Session Priorities
1. [Priority 1]
2. [Priority 2]
3. [Priority 3]

`;

    appendFileSync(progressPath, sessionEntry);

    console.log(chalk.green(`\n✅ Created Session ${nextSessionNum} in claude-progress.txt\n`));
    console.log(chalk.dim(`Title: ${title}`));
    console.log(chalk.dim(`Date: ${today}`));
    console.log();
    console.log('Next steps:');
    console.log(`  1. Edit ${chalk.cyan('claude-progress.txt')} to fill in session details`);
    console.log(`  2. Work on features from ${chalk.cyan('features.json')}`);
    console.log(`  3. Run ${chalk.cyan('harness log "message"')} to add quick notes`);
  });

// Log command - append quick note to progress file
program
  .command('log <message>')
  .description('Append a quick note to claude-progress.txt')
  .option('-p, --path <path>', 'Path to project directory', '.')
  .action(async (message: string, options) => {
    const targetDir = resolve(options.path);
    const progressPath = resolve(targetDir, 'claude-progress.txt');

    const { existsSync, appendFileSync } = await import('node:fs');

    if (!existsSync(progressPath)) {
      console.log(chalk.red('❌ claude-progress.txt not found'));
      console.log(chalk.dim(`Expected at: ${progressPath}`));
      process.exit(1);
    }

    const timestamp = new Date().toISOString().replace('T', ' ').split('.')[0];
    const logEntry = `- [${timestamp}] ${message}\n`;

    appendFileSync(progressPath, logEntry);

    console.log(chalk.green('✓ Added to progress log:'));
    console.log(chalk.dim(`  ${logEntry.trim()}`));
  });

// Progress command - show parsed progress file
program
  .command('progress [project-path]')
  .description('Display parsed progress file with statistics')
  .option('--sessions <n>', 'Show last N sessions', '3')
  .action(async (projectPath: string | undefined, options) => {
    const targetDir = resolve(projectPath || '.');
    const progressPath = resolve(targetDir, 'claude-progress.txt');

    const { existsSync, readFileSync } = await import('node:fs');

    if (!existsSync(progressPath)) {
      console.log(chalk.red('❌ claude-progress.txt not found'));
      console.log(chalk.dim(`Expected at: ${progressPath}`));
      process.exit(1);
    }

    const content = readFileSync(progressPath, 'utf-8');

    // Parse sessions
    const sessionRegex = /## Session (\d+) - (\d{4}-\d{2}-\d{2}) - (.+)/g;
    const sessions: Array<{ num: number; date: string; title: string }> = [];
    let match;

    while ((match = sessionRegex.exec(content)) !== null) {
      sessions.push({
        num: parseInt(match[1], 10),
        date: match[2],
        title: match[3].trim(),
      });
    }

    console.log(chalk.bold('\n📜 Progress Log Summary\n'));

    // Show statistics
    console.log(chalk.bold('Statistics:'));
    console.log(`  Total sessions: ${chalk.cyan(sessions.length)}`);
    if (sessions.length > 0) {
      console.log(`  First session: ${chalk.dim(sessions[0].date)}`);
      console.log(`  Last session: ${chalk.dim(sessions[sessions.length - 1].date)}`);
    }
    console.log();

    // Show recent sessions
    const numToShow = Math.min(parseInt(options.sessions, 10), sessions.length);
    const recentSessions = sessions.slice(-numToShow);

    console.log(chalk.bold(`Recent Sessions (last ${numToShow}):`));
    for (const session of recentSessions) {
      console.log(`  ${chalk.cyan(`Session ${session.num}`)} - ${session.date}`);
      console.log(`    ${chalk.dim(session.title)}`);
    }
    console.log();

    // Count completed items
    const completedMatches = content.match(/^- \[?✅?\]?\s*.+$/gm);
    const inProgressMatches = content.match(/^- \[?🔄?\]?\s*.+$/gm);

    if (completedMatches || inProgressMatches) {
      console.log(chalk.bold('Task Summary:'));
      console.log(`  Completed items: ${chalk.green(completedMatches?.length || 0)}`);
      console.log(`  In progress: ${chalk.yellow(inProgressMatches?.length || 0)}`);
    }
  });

program.parse();
